/* cotTruyen q05 (51 chương) — engine-API cotTruyen */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q05"]=window.__LIBQ["tien-nghich"]["q05"]||{};window.__LIBQ["tien-nghich"]["q05"]["cotTruyen"]=[{"chuong":391,"tieuDe":"Đệ Nhị Chu Tước?","tomTat":"Suốt mấy tháng chu du non nửa Chu Tước Tinh cùng Độn Thiên, Vương Lâm nghe kể về Nạp Đa — một trong bốn người ngoại lai năm xưa đến từ Ngũ Hành Tinh, liền tiết lộ từng gặp lão, khiến Độn Thiên đoán Nạp Đa đã đột phá Vấn Đỉnh tới tầng giới hạn kế tiếp. Khi định tiến vào Chu Tước đại lục, cả hai bị Chu Tước kỳ trận — quầng sáng xanh bao phủ cả đại lục, uy năng sánh Vấn Đỉnh Hậu Kỳ — chặn đường. Đòn thử của Độn Thiên bị một nắm tay hư ảo đánh tan, hé lộ trận đã dung nhập máu và thần thông Cự Ma Tộc, do nhị đệ tử Kiền Phong giải phong ấn dẫn tộc này về phục vụ Chu Tước quốc. Bị ép, Kiền Phong xuất hiện mở lỗ hổng cho Độn Thiên vào rồi khép trận nhốt Vương Lâm bên ngoài để khiêu chiến. Trong cuộc đối đầu, Vương Lâm rút tiên kiếm dung nhập tiên lực chém một nhát cắt lời, ép Kiền Phong lui trăm trượng, khiến hắn kinh hãi nhận ra tiên bảo và ngón tay rỉ máu mà không hay @c0391."},{"chuong":392,"tieuDe":"Kiền Phong","tomTat":"Sau khi đánh lui Kiền Phong một kiếm, Vương Lâm lập tức ra tay toàn lực, triệu Thập Ức Tôn Hồn Phiên thả hàng triệu hồn phách cùng mười hai chủ hồn cướp tiên cơ, rồi hô lệnh cho hồn phách tự nổ tạo uy lực kinh người. Kiền Phong vốn coi thường nên trở tay không kịp, buộc phải rút Dùi Chu Tước rồi chuyển Chu Tước trận về hộ thân, dù phun máu chịu thương vẫn giữ được mạng. Vương Lâm đã dùng hết hai phân phiên hư ảo, không thể giết đối thủ trừ phi động dụng đệ tứ chủ hồn, nên thong dong rút về Luyện Hồn Tông. Kiền Phong tức giận gọi sư muội Hồng Điệp như con rối không hồn ra hút sinh mệnh lực chữa thương, thề giết Vương Lâm để nuốt ý cảnh và đoạt Tôn Hồn Phiên mà sư tôn cũng đang nhắm tới. Độn Thiên dẫn Vương Lâm vào cấm địa sau núi bế quan chờ Anh Biến, giao túi trữ vật và hứa hộ pháp. Một mình ngồi canh, Độn Thiên độc thoại cùng chủ hồn sư huynh, hé lộ tuổi thọ sắp hết và quyết tâm bỏ luân hồi thành chủ hồn, mong Vương Lâm sau này lưu lại huyết mạch cho Luyện Hồn Tông giữa cơn nguy khốn do Tiên Di Tộc tấn công. @c0392"},{"chuong":393,"tieuDe":"Anh Biến (Chung)","tomTat":"Vương Lâm ngồi trong động phủ cấm địa, mở túi trữ vật Độn Thiên để lại và sững người vì lượng tiên ngọc cướp đoạt từ các tông phái nhiều gấp trăm lần số hắn tự lấy ở tiên giới, đủ hiểu vì sao Luyện Hồn Tông mấy vạn năm xuất nhiều Anh Biến tu sĩ. Hắn đổ tiên ngọc khắp nơi rồi thổ nạp hấp thụ, ép linh lực ngưng thành linh cầu nơi đan điền, dùng tiên lực xóa từng chút phàm căn thay cho Tẩy Linh Trì đã mất tích cùng tiên giới sụp đổ. Sau khi linh cầu hóa kim rồi nổ tung, nguyên thần bị đánh văng ba thước và bị lực đạo ngăn không cho trở vào, đành lơ lửng quan sát thân thể tự tái tạo kinh mạch bằng tiên lực, trở nên trong suốt như thủy tinh, quần áo hòa tan, cả người như tiên nhân — bước một thân thể ngưng hóa hoàn thành. Thân thể bắt đầu tỏa hương khí mê người có thể dẫn dụ yêu thú và lệ hồn đến đoạt xá, nên Độn Thiên hộ pháp bên ngoài, bố trí lồng khí đen ngăn hương, dựa Tôn Hồn Phiên và hộ sơn đại trận phòng bị. Cuối chương, nguyên thần Vương Lâm tự mở túi trữ vật đổ thêm tiên ngọc, lần này tiên lực không bị thân thể hút mà ngưng kết thấm vào nguyên thần, khởi động bước hai nguyên thần cô đọng @c0393."},{"chuong":394,"tieuDe":"Chu Tước Tử","tomTat":"Trong động phủ, Vương Lâm cảm nhận nguyên thần dần ngưng thật, tiến gần thành công Anh Biến, trong khi bên ngoài Độn Thiên đang thu hồn phách vào Thập Ức Tôn Hồn Phiên. Hộ sơn đại trận Luyện Hồn Tông bất ngờ nổ tung sụp đổ, Chu Tước Tử — đại thần thông Vấn Đỉnh Hậu Kỳ duy nhất hiện nay, người đứng đầu Chu Tước Tinh — hiện thân đòi 'mượn' Tôn Hồn Phiên theo lời hứa năm xưa giữa hai thế lực, nhưng Độn Thiên phủ nhận và khai chiến. Chu Tước Tử tung Chu Tước thánh hỏa phủ trăm dặm khiến cả Vương Lâm bị cuốn vào 'biến mất', còn Độn Thiên cắn lưỡi phun máu dung hợp ba mươi tư chủ hồn thành hồn phách Vấn Đỉnh Hậu Kỳ hóa người mây, hóa chín phi kiếm tiên lực vây công. Bị ép, Chu Tước Tử buộc dùng Chu Tước huyền ấn phòng thủ chống lại, tuy không bị thương nhưng tái nhợt mất vẻ phiêu dật vì lo giảm thọ trước đại chiến với Tiên Di Tộc. Cuối cùng lộ ra mục đích thật của hắn không phải cây phiên mà là chờ đệ tứ chủ hồn xuất hiện, bởi các đời Chu Tước Tử đã âm thầm nghiên cứu cách trừ khử nó và nay đã chắc tám phần. @c0394"},{"chuong":395,"tieuDe":"Thông Minh Sao Bằng Bậc Đế Vương","tomTat":"Bị Chu Tước Tử bức bách muốn tận mắt xem thần thông đệ tứ chủ hồn, Độn Thiên cắn răng rút cạn chút tuổi thọ cuối làm tế, gọi ra một chiếc tử kim châm bằng ngón tay cái — vật cứng nhất thiên hạ xuyên thấu mọi vật và tổn thương nguyên thần. Nhờ điển tịch Chu Tước Sơn lóe lên trong đầu, Chu Tước Tử nhận ra đó chính là 'Tam kim linh hồn', người gốc hiếm đạt ba phần một thuộc tính được Luyện Hồn Tông luyện chế. Tử kim châm đâm thủng cả Chu Tước Kiếm, rồi điên cuồng nuốt hồn phách khiến Tôn Hồn Phiên mất mười chủ hồn cùng một phần ba trong mười triệu hồn phách — tổn thất vạn năm chưa từng có, buộc Độn Thiên đau lòng ra lệnh dừng. Chu Tước Tử thâm hiểm chờ hồn nuốt thêm để mạnh hơn mới thu phục, dùng hỏa hồ tiên bảo tạo biển lửa trăm trượng luyện hóa và lén cài máu mình vào hồn, đó chính là 'thông minh sao bằng đế vương'. Lão tiếp tục hiến chín phần mười tuổi thọ mở tu tinh chi tâm, đoạt 'đình chỉ ý cảnh' khiến mọi sinh linh trăm trượng bất động, tóm gọn đệ tứ hồn vào tay rồi chụp về phía Độn Thiên. Đúng lúc nguy cấp, Vương Lâm từ nơi bế quan vọng ra tiếng cười âm trầm cùng câu mắng 'Cút con bà ngươi đi!', giáng đòn khiến Chu Tước Tử nguyên thần đau đớn, lộ vẻ kinh hãi chưa từng có. @c0395"},{"chuong":396,"tieuDe":"Tư Đồ Nam","tomTat":"Phía đông Chu Tước đại lục, vô số người Tiên Di Tộc khoanh chân đọc chú ngữ, luân phiên thôi thúc phù văn suốt mấy tháng để bày đại trận diệt Chu Tước quốc, với bốn phân nhánh cây tổ linh do hư tổ hi sinh phá ngũ kiếm phong ấn phóng thích vây quanh đại lục. Ngũ tổ Tiên Di Tộc — Chu Tước Tử đời thứ mười bốn mang ấn ký lá cây tím trên má — chủ trì trận pháp, bất đồng với nhị tổ về việc diệt quốc và uy lực Tu tinh chi tâm. Tư Đồ Nam (Tư Mã trưởng lão, Anh Biến Sơ Kỳ) của Thi Âm Tông cưỡi quan tài đến đưa thi thể và báo tin Chu Tước Tử đang đại chiến Độn Thiên lão quỷ ở Luyện Hồn Tông để tranh đoạt Thập Ức Tôn Hồn Phiên. Giữa lúc đó, Vương Lâm bất ngờ hiện ra trong trạng thái cuồng ngạo quỷ dị với quầng sáng lam sẫm âm hàn và mắt đầy tà khí, áp chế khiến Chu Tước Tử khiếp sợ toát mồ hôi lạnh, ngờ rằng không phải Vương Lâm thường ngày. Vương Lâm nể mặt Diệp Vô Ưu — tên thật của đệ nhất Chu Tước Tử và là người từng có đại ân với hắn — nên tha mạng, khiến Chu Tước Tử cung kính gọi 'lão tổ' rồi lui. Cuối cùng, Vương Lâm đồng ý cho Độn Thiên mượn đệ tứ hồn ba năm để đối phó Tiên Di Tộc, hẹn sau ba năm phải trả lại. @c0396"},{"chuong":397,"tieuDe":"Đồng Tử","tomTat":"Mượn thân Vương Lâm, một khí tức xa lạ cuồng ngạo ép đệ tam Chu Tước Tử tự cắt ba ngón tay đền tội rồi đuổi đi; Chu Tước Tử dù nghi ngờ đối phương chỉ vừa thức tỉnh và hư trương thanh thế vẫn không đủ dũng khí quay lại, đành ôm ý độc bay về Chu Tước Sơn. Sau đó người ẩn trong Thiên Nghịch Châu lộ diện chính là Tư Đồ Nam — đệ nhị Chu Tước Tử, sư phụ ma đạo năm xưa của Vương Lâm — vừa được lửa Chu Tước đánh thức, khiến Độn Thiên khiếp sợ tham kiến. Cảm kích Độn Thiên hộ pháp, Tư Đồ Nam xuất Thập Ức Tôn Hồn Phiên và hứa khôi phục Luyện Hồn Tông, để rồi vị trưởng lão Hóa Thần hồi tưởng cả đời, từ biệt sư môn và mãn nguyện hủy thần trí thành hồn phách nhập vào phiên. Vương Lâm cầm Tôn Hồn Phiên quỳ lạy ba lạy tiễn Độn Thiên, thề trở về báo thù việc Chu Tước Tử diệt môn. Tư Đồ Nam quyết tìm thân thể đồng tử thượng đẳng ở Viêm Cực cực bắc để đoạt xá khôi phục bản lãnh, dẫn Vương Lâm lên đường. Trên đường, sau khi kể công ơn cũ khiến Vương Lâm đồng ý cho mượn Văn Thú nghiên cứu, Tư Đồ Nam xem một sợi màu trắng tỏa áp lực như Thiên Kiếp thì lập tức biến sắc và vội cất nó trở lại túi trữ vật. @c0397"},{"chuong":398,"tieuDe":"Tu Tinh Chi Tinh","tomTat":"Đáp lại nghi vấn của Tư Đồ Nam, Vương Lâm kể lai lịch tia Cực Cảnh tự sinh trong cơ thể năm xưa ở Quyết Minh Cốc và đại thành sau khi rời chiến trường ngoại vực; Tư Đồ Nam cảnh báo đây là vật bá đạo bị tu chân liên minh năm nào cũng truy sát nên tuyệt đối phải giấu, nhất là Chu Tước Tử. Vương Lâm hoài nghi Cực Cảnh liên quan Hoàng Tuyền Thăng Khiếu Quyết, được Tư Đồ Nam thừa nhận khả năng nhưng còn nguyên nhân sâu xa, đồng thời hé lộ Tu Tinh Chi Tinh — vật ác độc nhất do liên minh khống chế, có thể khiến Cực Cảnh tiến hóa và cần đến nếu muốn rời Chu Tước Tinh. Đang kể dở thì Tư Đồ Nam phát hiện Tiên Di Tộc đang hiến tế tổ linh, nhớ tới thuật thần thông của đệ nhất Chu Tước Tử có thể hấp thu sức mạnh kỳ dị từ cây thần, bèn hút một khối tiên ngọc của Vương Lâm rồi biến mất hành động. Cùng lúc, khí tức cuồng ngạo khiến toàn bộ Vấn Đỉnh tu sĩ trên tinh cầu chấn động, Sở Vân Phi, một lão quái phương nam và Chu Tước Tử đều rời đi. Tại phía đông, Tư Mã trưởng lão Thi Âm Tông cùng hai thủ thi chấp sự mở quan tài, phun máu triệu ra thi thể Cự Ma Tộc hơn mười trượng có dấu lưỡi búa tím giữa lông mày để hiến cho cây thần. Đúng lúc đó Sở Vân Phi dẫn lực lượng Thiên Ngọc Tông phá màn sương đen, quyết chiến với ngũ tổ Tiên Di Tộc và bổ một chưởng xuống cỗ quan tài, mở màn đại chiến. @c0398"},{"chuong":399,"tieuDe":"Tổ Linh Thụ","tomTat":"Tại bốn hướng Chu Tước Tinh, Tiên Di Tộc khởi động bí thuật nuôi cấy tổ linh: ngũ tổ phía đông tạo màn sương đen, dùng kim mang ấn vào thi thể Cự Ma Tộc để mọc lên Luân Hồi thụ cao trăm trượng, sóng xung lực đẩy lui Sở Vân Phi khiến phe tấn công phía đông thất bại. Theo hiệp ước, ngũ tổ trao một tổ phù cửu diệp cho Tư Mã trưởng lão của Thi Âm Tông, đổi lại Thi Âm Tông chào hàng thân thể tổ tiên Cự Ma Tộc Vấn Đỉnh Trung Kỳ từng giết mấy cửu diệp thuật chú sư. Kết cục bốn hướng: chỉ Chu Tước Tử phía tây phá hủy thành công, đông và nam đều thất bại, còn phía bắc xảy ra biến cố lớn. Tư Đồ Nam lén vào màn sương đen, ký sinh hư ảnh trong Luân Hồi thụ và nuốt sạch dinh dưỡng khiến cả một tổ linh sụp đổ tan biến, khiến tứ tổ đầu bạc phẫn nộ hy sinh phù văn truy kích điên cuồng. Tư Đồ Nam trêu chọc tứ tổ rồi tìm Vương Lâm, ôm hắn vọt khỏi Chu Tước đại lục bay thẳng tới Viêm Cực ở tiểu bắc. Hắn mưu tính nuốt tổ linh kết hợp thân thể rồi quay lại nuốt luôn Vương Lâm để rút ngắn nửa thời gian khôi phục, coi như cũng diệt giúp một thuật chú sư cỡ Vấn Đỉnh Kỳ. @c0399"},{"chuong":400,"tieuDe":"Tiểu Bắc Viêm Cực","tomTat":"Tiểu Bắc Viêm Cực nằm phía bắc Chu Tước Tinh là vùng băng đỏ nóng cháy chứa đầy cấm chế tự nhiên: khí Cửu Lê hủy diệt sinh linh, huyết chi quang thiêu đốt kẻ có huyết dịch và băng hấp thụ thần thức. Sâu trong nơi này, ma đồng tuấn tú của đại trưởng lão Tôn Thái (Thi Âm Tông) bị viêm băng vây khốn, vật vã chống lại khí Cửu Lê đang luyện hóa nó — đây vốn là vật đoạt xá xếp thứ 171 trong bảo giám, được tế luyện hơn ngàn năm thành thi thể Anh Biến Trung Kỳ, bị nhốt sau khi Tôn Thái bị thiên phú thần thông của lão tổ Cự Ma Tộc tống khỏi tinh cầu. Vương Lâm cùng Tư Đồ Nam (lão tổ Cự Ma Tộc) phá không tới Viêm Cực, bị tứ tổ Tiên Di Tộc kiên trì đuổi theo để đoạt lại tổ linh chưa bị luyện hóa. Tư Đồ Nam bấm quyết niệm chú kích hoạt cấm chế khiến băng toàn vùng phóng tinh quang, huyết chi quang chiếu tứ tổ làm da dâng hồng quang. Tứ tổ vốn hiểu rõ nơi này liền dùng phù văn đẩy tan bạch quang rồi hóa tơ quấn lấy địch, nhưng Tư Đồ Nam xuyên thẳng vào cơ thể hắn, bị cây cửu diệp ở mi tâm đẩy ra. Cuối cùng Tư Đồ Nam quát \"Sương Cửu Lê\", điều sương đen bao bọc cả hai rồi kéo về phía viêm băng đang vây khốn ma đồng. @c0400"},{"chuong":401,"tieuDe":"Bí Mật Của Tu Tinh Chi Tinh","tomTat":"Trong màn sương Cửu Lê làm hộ pháp, Tư Đồ Nam chui ra khỏi khối viêm băng, nhập vào cơ thể đồng tử để đoạt xá, hứa khôi phục bản lãnh rồi sẽ giúp Vương Lâm và dặn hắn cẩn thận Chu Tước Tử. Hắn tiết lộ bí mật Tu Tinh Chi Tinh: do tu chân liên minh dùng thuật tế trời tạo ra, ban cho tu chân quốc cấp sáu, hấp thụ một mệnh hồn của mọi sinh mệnh sinh ra trên tinh cầu, là thủ đoạn khống chế tối thượng mà năm xưa hắn từng phong ấn khiến Chu Tước Tinh nay đại loạn. Hắn cũng nói về Tu Tinh Chi Tâm cho phép Chu Tước Tử hiến tế thọ nguyên để giết người, và cảnh báo một tia mệnh hồn Vương Lâm vẫn còn bị giữ trong Tu Tinh Chi Tinh nên buộc phải rút ra mới yên ổn. Nghe vậy, Vương Lâm vỡ lẽ vì sao các tu chân quốc làm phản và vì sao Tiên Di Tộc chưa bị tiêu diệt, đồng thời thầm cảnh giác không để sinh mệnh mình nằm trong tay kẻ khác. Hắn lập kế hoạch rút mệnh hồn, thu du hồn khôi phục Thập Ức Tôn Hồn Phiên, tìm huyết dịch Cự Ma Tộc ở Thi Âm Tông rồi đi tìm Thiên Vận Tử, đặc biệt gấp rút rời Chu Tước Tinh vì mối đe dọa Thác Sâm thừa hưởng sức mạnh bát tinh của Đồ Ti. Cuối cùng hắn đổi hướng bay về Sở quốc thăm nhà, ẩn tàng thân hình xuyên qua đại chiến lần hai khi Tiên Di Tộc tràn ngập khiến toàn Chu Tước đại lục chìm trong máu tanh. @c0401"},{"chuong":402,"tieuDe":"Chấp Hành Giả - Kẻ Chấp Hành","tomTat":"Trên Chu Tước Tinh, Tiên Di Tộc sau mấy vạn năm im lặng lại tổng phản công; ba tu chân quốc cấp năm Thủy Mặc, Mẫu Đơn và Tần đồng loạt làm phản khiến Chu Tước quốc tan tác, buộc co phòng tuyến về Chu Tước đại lục. Vân Tước Tử — sư đệ Chu Tước Tử — bất ngờ lộ thân phận nhị tổ Tiên Di Tộc, đánh lén trọng thương Chu Tước Tử, đồng thời sai hư ảnh nhất tổ đánh đuổi Sở Vân Phi khỏi Chu Tước Tinh; hắn cho Chu Tước Tử ba tháng dưỡng thương để hẹn quyết chiến dưới Chu Tước Sơn, thực chất chờ đối phương hiến tế Tu Tinh Chi Tinh rồi mới ra tay. Vân Tước Tử tiết lộ \"kế hoạch Chu Tước\": bồi dưỡng bốn quân cờ Kiền Phong, Liễu Mi, Chu Võ Thái và Vương Lâm làm Chu Tước Tử kế nhiệm, trong đó coi Vương Lâm là \"chấp hành giả\" then chốt. Bên cổ truyền tống trận, Chu Võ Thái đội Vân Tước mão tìm gặp Vương Lâm cùng uống lại rượu năm xưa, cảnh báo cả bốn đều là quân cờ và Vân Tước Tử có tư tâm với hắn, rồi để lại ngọc giản ý cảnh Thiên Huyễn vô tình đạo của Liễu Mi. Vương Lâm xem xong miết vỡ ngọc giản, trở về Sở quốc nay tan hoang dưới sự khống chế của Tiên Di Tộc, về thôn cũ không một bóng người. Vốn định rời đi thu thập du hồn ở chiến trường ngoại vực, nhưng cuối cùng nội tâm hắn thay đổi quyết định. @c0402"},{"chuong":403,"tieuDe":"Cưu Chiếm Thước Sào","tomTat":"Trước khi rời Chu Tước tinh, Vương Lâm nhắm vào kho dự trữ vạn năm của Tiên Di tộc và quyết đột nhập hố sâu, nhưng bị cái cây khổng lồ chọc trời phòng vệ chặn không thể vào. Qua thử nghiệm bằng linh quang và phân thân tượng gỗ đều thất bại, hắn phát hiện cây chỉ ngăn vật mang linh lực còn hồn phách có thể tùy ý xuyên qua. Hắn điều hơn hai ngàn hồn phách trong thiên Hồn Phiên, gồm cả tàn hồn Kỳ Lân thú, tụ thành bộ khải giáp bao quanh nhục thân và xuyên vào bên trong. Nhờ tu vi gần đạt Anh Biến sơ kỳ, hắn thuấn di nhanh chóng qua tầng một, hai, ba vắng lặng rồi ẩn thân ở cửa tầng bốn. Bám theo một Thuật Chú Sư lục diệp dẫn đám tu sĩ vô thần, Vương Lâm lặng lẽ tiến vào trung tâm mà không bị phát hiện. Tại đó hắn chứng kiến mười một lục diệp Thuật Chú Sư niệm chú đẩy phù văn kích Luân Hồi thụ, để rễ cây quấn hơn trăm tu sĩ Kết Đan kỳ hút tinh huyết và linh lực chuyển hóa thành lực chữa thương cho một bát diệp Thuật Chú Sư trọng thương — kẻ duy nhất có tư cách phát hiện ra hắn. @c0403"},{"chuong":404,"tieuDe":"Tổ Phù Đầu Cốt","tomTat":"Trên tầng thứ tư của không gian Luân Hồi thụ, Vương Lâm hóa hư ảnh áp sát lão giả bát diệp Thuật Chú Sư đang chữa thương, vỗ một chưởng tiên lực kinh thiên động địa khiến đám lục diệp khiếp sợ nhận ra hắn là tu sĩ Anh Biến rồi bỏ chạy. Hắn phá vỡ Luân Hồi thụ giải cứu hơn trăm tu sĩ bị giam, trong đó một tu sĩ Kết Đan kinh ngạc gọi hắn là 'Thủy tổ', rồi thả Văn thú hút khô những kẻ chạy trốn. Truy sát lão giả — vốn là trưởng lão Tiên Di tộc bên cạnh ngũ tổ đại nhân định chạy lên tầng mười một cầu cứu tam tổ — Vương Lâm rút tiên kiếm chém vỡ Tổ phù, đánh một ấn ký rồi chém đầu lão. Kiểm tra bằng bí thuật Luyện Hồn tông, hắn phát hiện đầu lâu không có hồn phách, lại không tan dưới u hỏa và mang một phù hào đen không trọn vẹn giống hệt Tổ phù, bèn thu vào túi trữ vật. Khi tiến vào tầng thứ năm rộng lớn phủ đầy tảo biển mê hoặc, hắn vừa phát hiện ba gốc Luân Hồi thụ với bát diệp trọng thương thì tảo biển bỗng mọc dày, kết thành vô số sinh vật hình người quỷ dị vây quanh hắn. @c0404"},{"chuong":405,"tieuDe":"Tam Tổ Là Nàng","tomTat":"Xâm nhập sào huyệt Tiên Di tộc, Vương Lâm dùng Thập Ức Tôn Hồn Phiên dung hợp khoảng năm triệu hồn phách cùng hơn mười chủ hồn thành một hồn phách tu vi Vấn Đỉnh sơ kỳ để phá vòng phòng thủ. Hắn điều hồn phách này càn quét từ tầng năm xuống tầng mười, hủy các Luân Hồi thụ và giết tổng cộng mười chín bát diệp Thuật Chú Sư đang chữa thương, cướp lượng lớn linh thạch cùng mười chín đầu lâu chứa tinh hoa phù văn thượng cổ. Tới tầng mười, hồn phách Vấn Đỉnh suy yếu tan rã không thể gọi lại, hắn thu hồi Hồn Phiên và xác nhận thuật ngưng tụ này tổn hại lớn nên năm xưa Độn Thiên hạn chế dùng. Cảm thấy có thứ dưới sâu kêu gọi, hắn bày một truyền tống trận ẩn từ ngọc giản Độn Thiên rồi nhảy xuống tầng mười một âm hàn đầy phù văn máu. Tại đó hắn thấy một nữ tử xích lõa lơ lửng, trán lóe phù văn cửu diệp, dung mạo mỹ lệ hiếm có và mang cảm giác quen thuộc, phía trên là bức tranh chín điểm sáng giống y hệt bức tranh không thể điều khiển trong túi trữ vật của hắn. Khi nữ tử mở mắt, kiếm hồn Hứa Quốc Lập biến ảo hiện ra nhận ra nàng là 'Tiên tử tiểu muội muội' và cảm tạ nàng đã mang về tia ý cảnh do tàn hồn năm xưa hắn bị mất. @c0405"},{"chuong":406,"tieuDe":"Ngươi Đồng Ý, Xuân Phong Nhất Độ","tomTat":"Tại tầng thứ mười một vùng đất Tiên Di, Vương Lâm đối mặt nữ tử thần bí tự xưng Mị Cơ — tam tổ Tiên Di Tộc; nàng áp chế Hứa Lập Quốc, phong tỏa lối ra và đòi gần gũi hắn mới cho đi. Vương Lâm phán nàng đang trọng thương chưa lành, lấy Thập Ức Tôn Hồn Phiên và tiên kiếm uy hiếp rồi bất ngờ kích hoạt Truyền Tống Trận tự bố trí để thoát thân. Mị Cơ phái Phù Thú Đồ Phổ — bảo vật Tiên Di Tộc — hóa giao long nghìn trượng và hắc hổ trăm trượng truy sát hắn từ tầng mười lên cửa tầng một. Vương Lâm tung ra cuộn Phù Thú Đồ Phổ của mình mà lâu nay không khống chế được, để nữ tổ tiên tự phong ấn bên trong vẫy tay thu cả hai phù thú, khiến Mị Cơ phun máu chịu phản phệ và hiện gốc cây cửu diệp trên trán để cưỡng thu lại. Hắn rời vùng đất Tiên Di trong đêm khuya, giữ lại ý cảnh tàn hồn của tam tổ làm thủ đoạn tối hậu. Đồng thời tại cấm địa sau Chu Tước Sơn, Chu Tước Tử độc thoại lộ thân phận thật, mối hận với Kiền Bình Hải, việc đoạt Tu Tinh Chi Tâm cướp ngôi cùng âm mưu nuôi Kiền Phong báo thù và ván cờ ba tháng với Vân Tước Tử quanh Tu Tinh Chi Tinh. @c0406"},{"chuong":407,"tieuDe":"Người Khổng Lồ Bên Dưới Thi Âm Tông","tomTat":"Tại phòng tuyến phía tây Chu Tước đại lục chống Tiên Di Tộc, Kiền Phong ngồi trấn giữ và khống chế Hồng Điệp, ngầm mưu tính nuốt ý cảnh của Tằng Ngưu cùng sư muội rồi rời Chu Tước Tinh, đồng thời nghi ngờ ý đồ của Chu Tước Tử khi lão đưa cho hắn một pháp bảo uy lực. Một tháng sau, Vương Lâm rời vùng Tiên Di, dùng Truyền Tống Trận của Sở quốc ra vực ngoại chiến trường thu du hồn hòng khôi phục Thập Ức Tôn Hồn Phiên, nhưng cả thuật du hồn lẫn thôn hồn đều thất bại vì hai bên trời sinh xung khắc như nước với lửa. Hắn chuyển mục tiêu sang thân thể khổng lồ của tổ tiên Cự Ma Tộc nằm sâu dưới Thi Âm Tông Triệu quốc, định lấy lượng lớn huyết dịch để Bổn Tôn thi triển thần thông cổ thần, chuẩn bị rời Chu Tước Tinh đi Thiên Vận Tinh bái sư tu tới Vấn Đỉnh Kỳ. Vương Lâm phá trận pháp, đạp xuống mắt trận và hiện ra trong mê cung hang động dưới lòng đất, nơi tông chủ Lý Thanh Bình đang bế quan chờ thây ma chiếm thân để lên Hóa Thần. Bất ngờ, hư ảnh màn sương đen sau lưng Lý Thanh Bình — một nguyên thần Hóa Thần Trung Kỳ — nhận ra Vương Lâm, kinh hãi kêu \"Tiền bối\" và khai mình là đệ tử Di Lặc Tông Thiên Vận Tinh phải mua thân từ Thi Âm Tông; Vương Lâm lạnh lùng tra hỏi vì sao người Thiên Vận Tinh lại đến Chu Tước Tinh. @c0407"},{"chuong":408,"tieuDe":"Tào Nhất Đấu","tomTat":"Vương Lâm tra hỏi hư ảnh ẩn trong thân Lý Thanh Bình ở Chu Tước Tinh, biết đó là Tào Nhất Đấu — một Hóa Thần tu sĩ vì không đủ tiên ngọc nên chọn nơi rẻ để đoạt xá điều dưỡng, dáng vẻ thành thực khiến hắn nhớ tới Hứa Lập Quốc năm xưa. Khi Lý Thanh Bình tỉnh dậy khiếp sợ đoán ra 'Anh Biến lão quái', Vương Lâm liền cách không bắt nguyên thần Tào Nhất Đấu và ra điều kiện làm nô bộc trăm năm để dẫn đường tới Thiên Vận Tinh, đổi lại một thân thể Anh Biến Kỳ cùng lời hứa 'ta không chết thì ngươi cũng không chết'. Tào Nhất Đấu bái chủ, Vương Lâm đánh Lý Thanh Bình hôn mê để giấu ý định rồi thu hắn vào cây hồn phiên vốn chế ra để thu Lý Nguyên Phong. Sau đó Vương Lâm trở lại nơi bế quan năm xưa, thân vào dễ dàng nơi từng phải dựa sương Thiên Nghịch Châu mới dò xét được. Hắn phá vỡ các tầng phòng ngự khí âm hàn từng chặn mình, mặc kệ tiếng 'Cứu ta' vọng vào linh hồn giống hệt thuở trước, tiến tới cỗ quan tài người khổng lồ. Cuối cùng hắn vào được hang động khổng lồ với đám sương trắng âm hàn nồng đậm và dải dây leo màu tím quay cuồng ẩn hiện trong đó @c0408."},{"chuong":409,"tieuDe":"Cứu Ta","tomTat":"Vương Lâm thi triển pháp thuật bậc thấp \"Phong động\" nhưng ẩn chứa tiên lực, cuốn tan đám sương trắng âm hàn, lộ ra một thi thể đàn ông khổng lồ da xanh bị cây ký sinh xanh tím bao phủ và một pháp thuật thần kỳ giam cầm. Qua dấu ấn hình lưỡi búa giữa lông mày, hắn quả quyết đây là tổ tiên Cự Ma Tộc — kẻ năm xưa mang tộc từ tinh không vào Chu Tước Tinh và giết ba cửu diệp thuật chú sư Tiên Di Tộc — đồng thời lĩnh hội cách phân cấp thuật chú sư (bát diệp ≈ Anh Biến, cửu diệp ≈ Vấn Đỉnh Sơ). Khi Vương Lâm bước lên thân, cây ký sinh phun cành mang máu tấn công, hắn dùng lửa tiên lực buộc lui nhưng không dám hủy cây vì sợ phá vỡ sự giam cầm. Tiên kiếm đâm vào thân thể cứng rắn bị phản chấn đẩy lùi ba tấc, nên hắn bẻ cành cây ký sinh có chất lỏng ăn mòn làm vũ khí mới xâm nhập được cơ thể người khổng lồ. Hắn lấy bình ngọc hứng máu tươi, lạnh lùng cự tuyệt lời cầu cứu và lời hứa trọng bảo của tổ tiên Cự Ma Tộc vì biết thả ra sẽ chuốc họa truy sát. Cuối cùng Vương Lâm lấy cấm phiên lâu nay chưa dùng ra, định dùng để xử lý đám cây ký sinh @c0409."},{"chuong":410,"tieuDe":"Lôi Cát","tomTat":"Vương Lâm thúc cấm phiên hô 'Phong', hóa cấm khí thành lưới hắc quang phong ấn cái cây xanh tím trên ngực người khổng lồ, rồi dùng cành cây điểm vào cổ tạo ấn chú lấy máu tươi cùng sức sống vào bình ngọc với tốc độ nhanh hơn trước. Người khổng lồ tự xưng là Vạn Phu Hậu Cự Ma Tộc tên Lôi Cát, cầu được cứu, hứa làm vật cưỡi suốt đời và dâng trọng bảo Khai Thiên Chi Thiết cùng dịch thể cốt tủy, lại kể lể bị Thi Âm Tông phong ấn sau khi trọng thương dưới tay hai thập diệp thuật chú sư Tiên Di Tộc. Thấy Lôi Cát trả lời quá tỉ mỉ, giọng cố tỏ bình thường, Vương Lâm nhận ra hắn đang câu giờ nên thúc tiên lực ép máu chảy nhanh, gỡ phong ấn thu về cấm phiên rồi từ chối mọi lời dụ dỗ, quyết giữ Lôi Cát làm nguồn máu lâu dài và hóa khói rời đi. Sau khi hắn đi, Lôi Cát gào rít tiếc nuối vì chỉ thiếu nửa nén hương để máu cạn dưới một phần ba — khi ấy có thể đẩy đám cây ra mà nguyên thần xuất khiếu. Cái cây xanh tím đầy răng sắc chui ra từ xương sống, lan bọc gần một phần ba thân mình thành những đóa hoa tím hút máu sinh trưởng, còn Lôi Cát thề một ngày thoát ra sẽ không tha Thi Âm Tông @c0410."},{"chuong":411,"tieuDe":"Bất Đồng","tomTat":"Vương Lâm hiện thân tại Thi Âm Tông, dùng một hồn phách âm khí thả ra từ trước để dò xét hang động chỗ người khổng lồ — nơi có sức mạnh kỳ dị hạn chế thần thức; sau khi điểm vào hồn phách nhận tin, hắn cười lạnh rồi rời đi. Trên bình nguyên phía trên tông môn, Tư Đồ Nam đoạt xá thành công, hiện thân đồng tử áo đỏ độc ác, lại nuốt tứ tổ để đẩy nhanh dung hợp nên bản lãnh đạt Vấn Đỉnh Kỳ, rồi rủ Vương Lâm tới Phong Loan Tinh hưởng lạc nhưng bị từ chối. Tư Đồ Nam kể trọn lịch sử tu tiên hưởng lạc của mình: chu kỳ hưởng thụ rồi bị truy đuổi qua các cảnh giới từ Trúc Cơ, Kết Đan, Nguyên Anh, Hóa Thần đến Anh Biến, cùng quan hệ với Diệp Vô Ưu — người cứu hắn và rủ hắn lập nên Chu Tước quốc từ cấp bốn lên cấp sáu. Trong đại chiến với Tiên Di Tộc, Diệp Vô Ưu cùng vài lão bằng hữu hi sinh phong ấn địch nhân, trước khi chết ép Tư Đồ Nam làm đệ nhị Chu Tước Tử; còn hắn bị phá nát thân thể, trốn trong Thiên Nghịch Châu cho tới khi gặp Vương Lâm. Khi Tư Đồ Nam cho rằng cả hai đều tu tiên để hưởng thụ, Vương Lâm bình thản đáp 'Ta không giống như ngươi', khẳng định mình theo đuổi bản chất và đỉnh điểm tu luyện, muốn hiểu rõ thiên đạo chân tình. Tư Đồ Nam lần đầu nhận ra ở Vương Lâm một vẻ kiêu ngạo xa lạ mà hắn chỉ từng thấy ở đệ nhất Chu Tước Tử Diệp Vô Ưu. @c0411"},{"chuong":412,"tieuDe":"Trên Vấn Đỉnh","tomTat":"Chương mở đầu bằng hồi tưởng của Tư Đồ Nam về Diệp Vô Ưu — đệ nhất Chu Tước Tử có ân với hắn, người đã nâng Chu Tước Tinh từ tu chân quốc cấp bốn lên cấp sáu — và việc hắn thấy ở Vương Lâm dáng vẻ giống Diệp Vô Ưu khi xưa. Tư Đồ Nam nói rõ vùng Tu Tinh Chi Tinh chỉ Anh Biến tu sĩ mới vào được nên hắn không thể trợ giúp Vương Lâm rút mệnh hồn, song trấn an nếu thất bại vẫn có cách lấy lại. Hai người tạm biệt rồi cùng hóa cầu vồng bay đi, Tư Đồ Nam hẹn đến Phong Loan Tinh hưởng chức thân vương. Trên đường, hắn giảng giải cho Vương Lâm về cảnh giới sau Vấn Đỉnh: Vấn Đỉnh vừa là đỉnh vừa là ngưỡng khó vượt, đột phá thì tuổi thọ kéo dài gấp bội, còn không thì khó thoát thiên địa luân hồi. Hắn tiết lộ sau Vấn Đỉnh là Toái Niết Tam Cảnh (Khuy Niết, Tịnh Niết, Toái Niết), từ Vấn Đỉnh lên Khuy Niết phải qua hai cửa ải âm dương nhị ý, và giải thích Chu Tước Tử là danh hiệu do tu chân liên minh phong, nắm thần thông Chu Tước Ấn cùng pháp quyết Chu Tước Quyết truyền thừa. Cuối chương, Vương Lâm đưa thanh tiên kiếm cho Tư Đồ Nam kiểm tra; trong tay hắn kiếm phát kiếm quang ngập trời mạnh hơn gấp vô số lần, ngầm xác nhận đó là bảo vật cấp Toái Niết phi thường. @c0412"},{"chuong":413,"tieuDe":"Sự Điên Cuồng Của Chu Tước Tử","tomTat":"Tư Đồ Nam tùy hứng vung tiên kiếm xé toạc bầu trời thành khe nứt không gian phun gió lạnh hóa băng, qua đó luận với Vương Lâm rằng đây là tiên bảo bậc trung — một trong bốn thanh, hợp nhất sẽ thành tiên bảo bậc cao cực hiếm; lão còn thẩm định Khu Thú Quyển hóa Xạ Thần Xa là tiên bảo cấp thấp gần trung giai chế từ linh hồn tiên thú, mà Vương Lâm có tới ba cái. Chuyển cảnh, năm Tổ Tiên Di Tộc lần lượt vây Chu Tước Tử, trong khi Tu Tinh Chi Tinh giáng cơn đau đớn linh hồn lên toàn Chu Tước Tinh khiến Chu Tước Tử chợt hiểu ra đây là cạm bẫy hủy diệt của Liên Minh Tu Chân. Hắn cười lớn, vỗ tay mở Chu Tước Sơn nứt làm hai để lộ Chu Tước mộ, ra ván cờ sinh tử buộc Vân Tước Tử phải giành Tu Tinh Chi Tinh trước khi tinh cầu sụp đổ, không thì cùng chết. Kiền Phong, Liễu Mi, Thiếu tộc trưởng cùng tộc nhân Tiên Di Tộc và Chu Vũ Thái, Tử Tâm tranh nhau vào mộ lượt đầu, nhưng số người được vào bị hạn chế. Ngày thứ tư Vương Lâm cùng Tư Đồ Nam tới Chu Tước Sơn thì Chu Tước Tử và Vân Tước Tử đã biến mất, mười sáu tu sĩ Anh Biến giữ cửa chờ chỗ trống; nghe Tư Đồ Nam kể, Vương Lâm nhận ra Chu Tước mộ nguy hiểm hơn tưởng tượng gấp nhiều lần. @c0413"},{"chuong":414,"tieuDe":"Người Này Là Ai?","tomTat":"Vương Lâm nhẩm tính điều kiện rời Chu Tước mộ: cần ngọc giản Tư Đồ Nam đưa để rời đi và phải giành được Tu Tinh Chi Tinh mới rút được mệnh hồn, nếu không sẽ phải dùng biện pháp khác khiến linh hồn tàn khuyết. Khi hắn tiến vào Chu Tước Sơn, đám tu sĩ biến sắc nhường đường; tôn giả Man Hoang Nam Minh — lão già áo bào đen đang tôi luyện thân thể để đột phá Anh Biến — nhận ra thực lực hắn liền quát đệ tử kiêu ngạo câm miệng rồi cung kính bái kiến tiền bối. Vương Lâm được công nhận tư cách, gia nhập nhóm mười sáu tu sĩ được vào Chu Tước mộ nhanh nhất, đồng thời hé lộ cảnh giới Vấn Đinh nằm trên Anh Biến hậu kỳ. Một người đàn ông trung niên bí ẩn mang theo tiểu hầu bỗng gọi đích danh 'Tằng Ngưu', nhắc lại chiến tích giết Lý Nguyên Phong và toái diệt Cự Ma Tộc lão tổ, song Vương Lâm lạnh nhạt từ chối trò chuyện. Người này bóp con khỉ nhỏ khiến nó kêu gào mắt hóa đỏ, đúng lúc thông đạo Chu Tước mộ lóe ô quang mở ra, rồi quay đầu cười quỷ dị thầm nghĩ mình biết rõ Vương Lâm dù hắn không nhận ra. Đoàn tu sĩ ùa vào thông đạo, một tu sĩ Anh Biến sơ kỳ bị bắn ngược ra ngoài phẫn nộ quay về ngồi nắm chặt nắm đấm, còn Vương Lâm cũng phóng vào theo @c0414."},{"chuong":415,"tieuDe":"Linh Hồn Trên Vùng Đất Khô Cằn","tomTat":"Vương Lâm theo cánh cửa trên Chu Tước Sơn tiến vào Chu Tước Mộ, hiện thân giữa một vùng đất khô cằn mấy vạn dặm bốc khói đen, nhận ra nơi đây lớn hơn nhiều so với lời Tư Đồ Nam từng kể và không tìm thấy tế đàn dẫn vào trong. Khi sờ đất, hắn phát hiện linh lực thuộc tính hỏa sinh ra tự nhiên, vừa rời đi thì một đôi mắt thanh quang kỳ dị nổi lên nhìn theo. Tới biên giới vùng đất, hắn đối đầu một ngọn lửa xanh hút khói đen vạn dặm, chém kiếm mang hình vầng trăng phá khiên và rạch vết trên ngọn lửa. Ngọn lửa hóa thành đứa trẻ tám chín tuổi mắt đen kịt đòi giữ hắn ở lại, mà Vương Lâm nhận ra đây là hỏa linh khó giết, tồn tại vĩnh viễn cùng mảnh đất. Hắn quát đuổi rồi dùng thuật dịch chuyển né bức tường đất trăm trượng, thoát ra ngoài mấy vạn dặm. Đứa trẻ phóng hắc khí như giao long khiến cả vùng đất khô cằn chuyển động lao thẳng truy đuổi với tốc độ kinh người. Vương Lâm quay đầu, hút tiên lực từ tiên ngọc rót vào tiên kiếm cho phát ánh sáng tím chói rồi chém thẳng xuống bên dưới @c0415."},{"chuong":416,"tieuDe":"Mộ Dung Vân","tomTat":"Vương Lâm dùng tiên kiếm chứa tiên lực chém vỡ con đường mảnh đất khô cằn dài mấy vạn dặm, làm lộ ra một linh thể đứa bé cùng tiếng cười kỳ dị. Hắn dung thần thức vào tiên lực hóa thành tiên thức, phá cấm cố trên khối đất và tách được một mệnh hồn lửa xanh, nhận ra mỗi viên đất là một mệnh hồn phàm nhân và đứa bé là do nhiều mệnh hồn dung nhập thành. Nhớ lời Tư Đồ Nam về mệnh hồn nằm trong Tu Tinh Chi Tinh, hắn ngờ mệnh hồn của chính mình cũng ẩn trong một sinh vật như vậy. Hắn bay sâu vào Chu Tước mộ ba ngày, nơi linh lực đậm đặc vượt cả Tụ Linh Trận môn phái, nhưng không tìm được giới hạn lẫn một tu sĩ nào. Sau đó hắn gặp Mộ Dung Vân (Hóa Thần trung kỳ) cùng một cô gái mặt rỗ áo trắng, liền giấu tu vi giả làm Hóa Thần sơ kỳ và xưng danh cũ Thanh Mộc. Mộ Dung Vân mời đồng hành để tăng cơ hội thu mệnh hồn, tiết lộ Kiền Phong cùng các bát diệp Thuật Chú Sư Tiên Di Tộc đã vào sâu qua một tế đàn hẻo lánh đầy nguy hiểm. Chú ý tới đồ án tông phái và vệt máu đen trên áo đối phương, Vương Lâm cảnh giác rồi cười châm chọc rằng vận khí của Mộ Dung Vân quả không tồi @c0416."},{"chuong":417,"tieuDe":"Tế Đàn","tomTat":"Mộ Dung Vân cảnh báo Vương Lâm rằng nơi sắp tới có một người rất mạnh, cần thận trọng mới tiến vào được. Trên đường, cả nhóm chạm trán Mặc Vân Hải — một tu sĩ Anh Biến sơ kỳ trong nhóm mười sáu người ngoài Chu Tước Sơn — đang bị một tia chớp giao long trắng quỷ dị truy đuổi, và Mộ Dung Vân chỉ bằng một ánh mắt bình thản đã khiến tia chớp run rẩy bỏ chạy. Mặc Vân Hải ngộ nhận Vương Lâm là Tằng đạo hữu, sau đó cùng giao kèo: Mộ Dung Vân dẫn đường tới Tế Đàn để đổi lấy việc được vào trong, Vương Lâm và Mặc Vân Hải liên thủ bảo mệnh hắn. Bay toàn lực ba ngày, cả bọn tới dãy núi sương đen, nơi Vương Lâm âm thầm phun hắc mang và thả một vật để dò xét kín đáo. Trên đỉnh núi phía Tây hiện ra Tế Đàn đen hình tháp cao trăm trượng, nhưng Vương Lâm cảnh giác khi nhận ra vị trí khác hẳn lời Tư Đồ Nam từng kể (lẽ ra ở trong thung lũng). Mặc Vân Hải bất ngờ dùng Sưu hồn thuật moi hồn giết chết Mộ Dung Vân để xác nhận lời hắn không giả, rồi tự lao lên đỉnh Tế Đàn dò đường, nhờ Vương Lâm hộ pháp và cúi nhìn chỗ lõm phun hắc khí với sắc mặt cổ quái. @c0417"},{"chuong":418,"tieuDe":"Xinh Không Thể Tả Được!","tomTat":"Vương Lâm cách không đánh một đạo linh quyết vào mi tâm Mộ Dung Vân, vạch trần hắn thực chất là Linh vật do mệnh hồn biến thành giả dạng tu sĩ để cản người đến Tu Tinh Tinh, dựa vào ba dấu hiệu lộ tẩy về túi trữ vật, y phục lỗi thời và đồ án đặc biệt. Dùng Thập Ức Tôn Hồn Phiên khắc chế cùng cấm chế của Cấm Phiên, hắn ngưng kết Mộ Dung Vân thành khối cầu đen rồi phong ấn vĩnh cửu dưới hố hình chữ thập, ép đối phương khai ra bí mật. Mộ Dung Vân thú nhận chỉ \"Vương\" — Linh vật đầu tiên sinh ra trong Mộ địa, ngụ ở thâm cốc chín ngọn núi sương trắng hướng Đông — mới tùy ý rút được mệnh hồn từ Tu Tinh Tinh, qua đó hé lộ mục đích thật của Vương Lâm là thu hồi mệnh hồn của chính mình. Xen vào là tuyến phụ Kiền Phong, người đầu tiên tiến vào Chu Tước Mộ, đang phá hủy từng Linh vật đến cái thứ sáu mươi chín để chờ gặp mệnh hồn của mình và chứng kiến một tu sĩ Anh Biến chết ngay sau khi giết nhầm mệnh hồn liên đới chủ nhân. Rời đi, Vương Lâm đến thung lũng có Tế Đàn giống hệt trên đỉnh núi thì tái ngộ Liễu Mi xinh đẹp tuyệt trần đang ngồi chặn đường. Liễu Mi tiết lộ nàng tu Thiên huyễn vô tình đạo, cho rằng ý cảnh sinh tử luân hồi của Vương Lâm cũng là vô tình chi đạo nên hai người là cùng một loại, muốn mượn ý cảnh của hắn để viên mãn dù sư phụ Chu Tước Tử sắp tử vong ngăn cản. Khi Vương Lâm rút kiếm tiên thi triển Nhất kiếm trùng thiên, Liễu Mi triệu hư ảnh Khổng Tước dùng lông chim đỡ kiếm, còn hắn hóa Cấm Phiên thành trường thương đen lóe chớp tím tràn ngập hồng hoang khí, chuẩn bị toàn lực khai chiến. @c0418"},{"chuong":420,"tieuDe":"Một Huyễn Cuối Cùng","tomTat":"Liễu Mi qua Khổng Tước/Hoạ trục sinh tử luân hồi tuyên bố đã tu được chín trăm chín mươi chín \"huyễn\", chỉ thiếu một \"huyễn\" cuối để thành Thiên huyễn, đồng thời vạch ra sơ hở trong ý cảnh sinh tử của Vương Lâm là miệng nói sống chết nhưng lòng chưa thật sự đạt được. Vương Lâm lạnh lùng tung sát chiêu giấu kín: thả đám sương đỏ tia ý cảnh Mị Cơ chí âm chí dâm từ túi trữ vật vào Hoạ trục, dùng dâm dục bài trừ vô tình đạo của Liễu Mi. Mị Cơ ngưng thật thành nữ tử lõa thể yêu dị, hoá bụi phấn chui vào hai mắt Khổng Tước khiến nó sụp đổ, buộc Liễu Mi lộ thân ngồi trên Tế Đàn. Bất kể Mị Cơ có nuốt được Liễu Mi hay không, Vương Lâm tiến lên vào Tế Đàn để truyền tống tới Chu Tước Mộ, tính tìm mộ Chu Tước Tử hoặc Linh vật chi Vương thu lại mệnh hồn rồi rời đi, trong lòng lo Thác Lâm sắp thoát ly trói buộc Cổ Thần. Ở Chu Tước đại lục, Nhất tổ, Tam tổ, Vân Tiên Tử cùng hai mươi Diệp tổ linh Tiên Di Tộc hiến tế đầu lâu Hư tổ chứa thần lực để đưa một người vào Chu Tước Mộ. Đúng lúc bàn ai sẽ đi, Tam tổ biến sắc khi cảm nhận tia ý cảnh năm xưa của chính mình — Mị Cơ — đang đoạt xá nơi Chu Tước Mộ, hừ lạnh quyết không để nó như ý. @c0420"},{"chuong":422,"tieuDe":"Mệnh Hồn Của Lý Mộ Uyển","tomTat":"Vương Lâm tiến sâu vào Chu Tước Mộ, nhắm thẳng linh sơn trung tâm nơi lưu giữ Chu Tước Ấn và thi thể một đời Chu Tước Tử, vì biết thời gian tìm phương pháp bảo mệnh của Tư Đồ Nam không còn nhiều. Chương hé lộ cơ chế Tu Tinh Tinh và mệnh hồn: chỉ tu sĩ Vấn Đỉnh kỳ qua Vấn Đỉnh Triêu Văn đạo cùng cảm ngộ Tịch Tử Hĩ mới có cơ may rút mệnh hồn, song Tu Tinh Tinh đã bị Tư Đồ Nam phong ấn khiến cả Tiên Di Tộc trên Chu Tước tinh đều bất lực. Mạch truyện chuyển sang Thiên Vận tinh khổng lồ và Thiên Vận Tông coi trọng vận duyên, nơi Thiên Vận Tử hồi tưởng năm xưa thu một kẻ Hóa Thần cảm ngộ luân hồi sinh tử, đi ngược dòng luân hồi căn nguyên làm trăm năm ký danh đệ tử, nay đoán kẻ đó sắp đến nhưng lo hắn chưa đạt Hóa Thần hậu kỳ. Trở lại Chu Tước Mộ, Vương Lâm thận trọng né các Linh vật mệnh hồn rồi đến khe hai núi cao chọc trời giữa lộ tuyến, nhận ra vách đá ẩm ướt là giả khi khoét lỗ mười thước thấy bên trong khô ráo. Hắn lui kịp khỏi đường nhỏ, lập tức hơn mười vạn giọt nước — mỗi giọt một mệnh hồn — ngưng tụ thành một nữ tử thủy mệnh hồn khí tức quỷ dị, lạnh lùng cảnh cáo cấm vào, buộc Vương Lâm chậm rãi lui ra tìm đường vòng. @c0422"},{"chuong":423,"tieuDe":"Đoạt Hồn","tomTat":"Phát hiện trong thung lũng Chu Tước Mộ có thuỷ mệnh hồn lạ khiến tâm thần tương liên, Vương Lâm nhận ra đó chính là tiếng gọi yếu ớt của Lý Mộ Uyển trong Thiên Nghịch Châu nên không do dự xông vào. Hắn ném kiếm tiên phá vòng cản, phân nguyên thần thành vô số phong ấn từng giọt nước, rồi đối đầu Tiên Di Chi — lão già lưng còng năm xưa từng đuổi giết hắn nay căm phẫn quay lại. Vương Lâm xuất Thập Ức Tôn Hồn Phiên, thả Kỳ Lân tím vàng cùng đám Chủ Hồn Anh Biến kỳ đẩy lui lão, rồi dung hợp sáu Chủ Hồn vây giết nữ tử thuỷ mệnh hồn giống Uyển nhi, ép nàng hoá hơi nước để lộ mệnh hồn. Đúng lúc đó toàn bộ Tu Tinh Tinh động đất sụp đổ, vô số khe thứ nguyên nứt mở giết chết khôn xiết tu sĩ — tất cả do Chu Tước Tử cố ý. Giữa đại kiếp, Vương Lâm bắt được giọt nước trong suốt chứa mệnh hồn Lý Mộ Uyển, suýt mất mạng và mất một mảng góc áo, rồi đặt nó dung nhập Thiên Nghịch không gian. Tiên Di Chi mất nửa thân, nguyên thần chạy trốn cũng bị khe thứ nguyên cắn nuốt mà tan biến. Xa nơi ấy ở Toái Tinh Loạn thuộc Tu Ma Hải, một kẻ bí ẩn toàn thân tử khí với hư ảnh rừng xương đang đói khát đánh hơi hương vị thượng cổ tu sĩ, do dự có nên bước vào hay không. @c0423"},{"chuong":424,"tieuDe":"Sứ Giả Của Thác Lâm","tomTat":"Phá Quân đạp tảng nước biển khổng lồ tới Chu Tước Tinh, gọi đích danh xua đuổi lão già tử khí Tham Lang, khiến hắn chán ghét nhường nơi này hóa vòng cung đen rời đi; Phá Quân thu tinh thể thâm lam rồi tiến vào Toái Tinh Loạn vì nghi nơi đây giấu dị bảo. Sâu trong Cổ Thần chi địa, trên thạch truỳ giữa biển máu, Thác Lâm — Cổ Thần tộc tóc đỏ mắt đỏ bị phong ấn — độc thoại về kế hoạch thoát khốn: dung hợp tinh thể ký ức truyền thừa cuối cùng, lợi dụng phong ấn rạn kẽ do Tu Chân Tinh trưởng thành mà thi triển Hoán Hồn Thuật để rời đi, đồng thời đòi Vương Lâm giữ ký ức truyền thừa của hắn. Hắn cảm tạ Đồ Ti và Cổ Thần Hiến tế, tự nhận đã âm thầm thúc tiểu bối Tiên Di Tộc từ Thập Nhất Diệp lên Thập Nhị Diệp để toàn tộc thoát phong ấn, mở ra Tu Chân tinh chi địa, rồi cười điên cuồng tuyên bố sẽ nuốt truyền thừa của Vương Lâm thành Bát tinh Cổ Thần. Hai con khỉ nhỏ mắt đỏ của Thác Lâm thao túng lão già Tham Lang trong Chu Tước Mộ, điều khiển hắn đổi hướng về trung tâm, né các khe thứ nguyên. Vương Lâm cau mày truy theo, hai ngày sau lạc vào vùng lòng chảo Kim mệnh hồn với mấy vạn hố trũng cắm trường kiếm, kiếm ý dày đặc. Từ những hiện tượng khác xa lời Tư Đồ Nam, hắn suy đoán Chu Tước Mộ chính là Tu Tinh Tinh và quyết tới trung tâm kiểm chứng bằng việc có hay không có Linh Sơn @c0424."},{"chuong":425,"tieuDe":"Kỳ Bảo!","tomTat":"Thần thức Vương Lâm chấn động khi cảm nhận tại hố trũng lớn nhất ở trung tâm có cỗ kiếm khí bá đạo quen thuộc tựa bảo vật Tiên giới, liền triệu hồi kiếm hồn Hứa Lập Quốc để khắc chế đám kiếm hồn canh giữ và mở đường vào trong. Hắn ép Hứa Lập Quốc nhát gan xông vào trung tâm, bức một thanh loan nguyệt đao từ sương thâm lam bay ra, kinh ngạc nhận ra đao hồn này chỉ do MỘT mệnh hồn tạo thành — khác hẳn mọi Linh vật trong Chu Tước Mộ — lại khiến vô số kiếm hồn thần phục. Khi giao chiến, loan đao hoá thành đao khổng lồ mười trượng chém ra đao mang khai thiên tích địa, uy lực ngang một kích toàn lực Anh Biến hậu kỳ, buộc Vương Lâm bung Thập Ức Tôn Hồn Phiên hoá khói đen mà tháo chạy. Giữa đường hắn gặp lại Chu Vũ Thái và một nữ tử che khăn đen quen mặt, cả hai sợ hãi than xui xẻo bỏ chạy. Ra khỏi vùng hố trũng, loan đao thoát khỏi lực kỳ dị giam hãm nên tốc độ tăng vọt mấy chục lần, xẹt qua Chu Vũ Thái lao thẳng tới Vương Lâm. Hắn liên tục thuấn di hướng về Linh Sơn ánh sáng bảy màu mà Tư Đồ Nam từng nhắc, song vẫn bị đao mang làm thương cánh tay trái rồi chân phải, thầm đánh giá loan đao là pháp bảo cực phẩm có thể khiến mình đầu rơi nếu trúng thêm một kích. @c0425"},{"chuong":426,"tieuDe":"Hồng Điệp","tomTat":"Vương Lâm tiếp tục giao tranh với thanh loan đao do một mệnh hồn cường đại cấu thành, tốc độ càng lúc càng nhanh khiến hắn hiểu vì sao Chu Tước Tử e dè hồn phách thứ tư; quyết đoạt mệnh hồn, hắn xuất kiếm tiên đánh văng Hứa Lập Quốc ra ngoài và bị loan đao lập tức cuốn đi, song nhờ tâm linh tương thông nên giữ Hứa Lập Quốc làm căn cứ truy tìm sau này. Nhắm tới Linh Sơn, Vương Lâm gặp lại Hồng Điệp — cố đối thủ từng là đại thiên kiêu Tuyết Vực quốc trăm năm Hoá Thần — nay tiều tụy với đôi mắt trống rỗng vì bị Kiền Phong khống chế. Kiền Phong (Anh Biến trung kỳ) xúi Hồng Điệp giết hắn rồi hoá bóng đen lao về Linh Sơn tìm mệnh hồn, hẹn tái kiến. Hồng Điệp khai chiến bằng trường kiếm đỏ bị Cấm Phiên chặn lại, thoáng hé lộ một tia thần trí thốt yếu ớt 'Giết… ta…' rồi lại chỉ còn chiến ý. Vương Lâm do dự nhưng vẫn dùng Cấm Phiên ngưng tụ trường thương ba trượng toả hắc khí đâm một thương gào rít vang xa; Hồng Điệp đâm khối băng đỏ vào mi tâm, hồng quang loé biến thành bộ giáp đỏ toả hàn khí, hiện như một chiến tiên với cây roi đen trong tay. @c0426"},{"chuong":427,"tieuDe":"Đỏ Bừng","tomTat":"Bị khống chế, Hồng Điệp dùng cây roi Côn Cực Tiên do Kiền Phong trao để tấn công Vương Lâm; roi hoá giao long đen va với trường thương gây khí lãng kinh thiên, có lúc đẩy Vương Lâm lui trăm trượng khiến hắn quyết chí đoạt bằng được cây roi từng lỡ tay. Áo giáp đỏ của Hồng Điệp phát khí tức cực hàn ngưng kết hư không thành băng điêu, song nàng vẫn lộ vẻ đấu tranh thống khổ, cầu Vương Lâm giết mình. Vì kiếm tiên đã mất kiếm hồn và không muốn dùng Tôn Hồn Phiên, Vương Lâm rút chiến phủ Cự Ma Tộc do Lão tổ triệu hoán trước khi chết, ngưng tụ một cỗ chiến ý chưa từng có. Tia thần thức thật của Hồng Điệp hiện trong đoá hoa hồng, kiêu ngạo gọi 'Tằng Ngưu, ra tay đi… Giết ta', nói sinh mạng mất thần trí lưu lại vô dụng. Cách ngàn dặm, Chu Vũ Thái cung kính theo Vân Tước Tử vào đám mây đỏ lao về Linh Sơn, bỏ mặc Tử Tâm đã rời đi. Vân Tước Tử được Tiên Di Tộc đưa vào Chu Tước Mộ nhờ phù văn đầu lâu Hư Tổ nhưng bị hạn thời gian, nên vội vã tới trung tâm — nơi một lão già mắt huyết quang kèm khỉ nhỏ đã chiếm chỗ, ngồi thổ nạp trước cái cửa khổng lồ có khe nứt như vết sẹo. Vương Lâm than 'Thiên chi kiêu nữ, kết quả cuối cùng lại rơi xuống như thế này, thật đáng buồn', nhìn ra hư ảnh ẩn chứa nỗi thương tâm sâu sắc. @c0427"},{"chuong":428,"tieuDe":"Như Điệp","tomTat":"Vương Lâm vung chiến phủ nhảy lên không bổ xuống Hồng Điệp một búa huỷ thiên diệt địa, còn nàng dù đủ thực lực vẫn chọn không chống cự cũng không né tránh, chỉ thu thần thức về mi tâm rồi mỉm cười kiêu hãnh hồi tưởng sư phụ cùng hai thân ảnh nam thuở xưa. Trước khi thân thể nứt vỡ hoá sương máu, nàng để lại lời trối nhờ Vương Lâm giết Kiền Phong, hứa sang năm sẽ có một đoá hoa hồng xanh lam nở ở cực bắc Chu Tước Tinh làm lễ vật, cùng tiếng vọng \"Đỏ bừng như điệp\". Hồng Điệp còn lưu lại ngọc giản ghi chép cảm ngộ ý cảnh vô hạn dục vọng cắn nuốt của Kiền Phong và một chiếc Côn Cực Tiên. Vương Lâm thu chiến phủ vào túi trữ vật, dùng trảo cách không lấy Côn Cực Tiên nhưng trên đó còn thần niệm cao thủ Vấn Đỉnh kỳ, phải ngưng hoá Vấn Đỉnh Chủ hồn của Thập Ức Tôn Hồn Phiên mới đoạt được hẳn, rồi bay về Linh Sơn. Tại đây, Vân Tước Tử cùng Chu Vũ Thái hạ xuống bằng cơn lốc đỏ, phát hiện một lão già đoạt xá với con khỉ trên vai vốn chỉ là rối; sau khi bị truy hỏi, lão xưng danh Mạc Lực Hải rồi nhắm mắt, ánh mắt bắn ra hung mang. @c0428"},{"chuong":429,"tieuDe":"Tề Tụ","tomTat":"Trên đỉnh Linh Sơn trong Chu Tước Mộ, Vân Tước Tử với tu vi Vấn Đỉnh nghi lão già mang khỉ nhỏ không phải người Chu Tước Tinh, đồng thời quan sát cánh cửa lớn giữa hư không — thông đạo duy nhất vào Mộ của một đời Chu Tước Tử, cần Tu chân tâm và độ vỡ nhất định mới mở. Các cường giả lục tục tề tụ: Kiền Phong, hai Bát Diệp thuật chú sư Tiên Di Tộc, tu sĩ áo xanh đeo mặt nạ ngăn thần thức. Chu Tước Mộ trải qua lần sụp đổ thứ hai kéo dài ba mươi tức, nuốt chết ba đạo vòng cung phá không và biến thông đạo thành cạm bẫy khe thứ nguyên không ai dám bước vào, khiến Vân Tước Tử thử ấn cửa nhưng thất bại. Tử Tâm che khăn đen dẫn bốn lão Hóa Thần đầy thương tích lên đỉnh nhờ Phù lỗi, chạm mặt Kiền Phong với hận ý cuồn cuộn lẫn thống khổ. Vương Lâm chật vật rách rưới lên đỉnh sau khi suýt táng thân dưới khe thứ nguyên, lần đầu hội ngộ Vân Tước Tử sau biệt ly và được ba người gọi bằng ba danh xưng khác nhau. Hắn ôm quyền tham kiến rồi vỗ túi trữ vật, thả từng đạo ô quang hóa thành đám tượng gỗ điêu khắc dâng cho Vân Tước Tử. @c0429"},{"chuong":430,"tieuDe":"Người Lòng Dạ Sắt Đá","tomTat":"Vương Lâm báo với Vân Tước Tử rằng lời tiền bối dặn năm xưa hắn đã hoàn thành trọn vẹn, rồi khoanh chân ngồi xuống trong khi Vân Tước Tử làm đám tượng gỗ biến mất và dõi nhìn cánh cửa lớn trong hư không. Hắn đã từ bỏ ý định đoạt Tu Tinh tinh vì không nỡ hy sinh toàn bộ sinh mệnh Chu Tước Tinh, chỉ muốn thu hồi mệnh hồn, song với kẻ thù thì vẫn tàn nhẫn như từng tuyệt diệt Đằng gia. Trên đỉnh Linh Sơn, hắn đối chọi ánh mắt với Kiền Phong rồi chú ý tới một lão già lưu nụ cười quỷ dị trên lối vào Chu Tước Sơn, kẻ khiến hắn cảm thấy bị uy hiếp và quen thuộc lạ thường. Liễu Mi đáp xuống tiến lại khích đạo tâm bằng cách nhắc tên Lý Mộ Uyển — vảy ngược của hắn — khiến Vương Lâm nổi sát khí doạ giết, suýt xuất Tôn Hồn Phiên, buộc nàng mỉm cười rời đi về phía Kiền Phong. Nhờ cảm ứng huyền diệu của Anh Biến tu sĩ, hắn xác định lão già chính là Thác Lâm, ma niệm sinh từ Cổ Thần Đồ Ti mà năm xưa hắn từng trêu chọc khi mới Kết Đan. Chương cũng hé lộ cơ chế truyền thừa Đồ Ti chia làm ký ức và lực lượng: Vương Lâm nắm ký ức đạt tam tinh Cổ Thần còn Thác Lâm giữ lực lượng bát tinh nhưng chỉ phát huy được tới năm tinh, nên hắn khao khát đoạt ký ức để chân chính thành bát tinh. @c0430"},{"chuong":431,"tieuDe":"Kim Giáp Đại Hán","tomTat":"Vương Lâm xác định Thác Lâm thực chất là một tia ma niệm của Đồ Ti sinh ra khi phân thần thất bại nên quyết đoạt lấy, đồng thời nhận ra con khỉ nhỏ trên vai lão già âm trầm mang khí tức huyết tu sĩ biển máu, chua xót nhớ tới Lục Dục Ma quân, Mạnh Đà Tử, Cổ Đế đã chết hoặc hoá huyết tu. Chu Tước Mộ sụp đổ lần thứ ba phạm vi lớn, linh vật mệnh hồn tử vong gây phản ứng dây chuyền khiến Chu Tước Tinh dần thành tử địa, còn Chu Tước Tử ngồi trong Chu Tước Sơn cười điên cuồng chờ 'đệ tử ngoan' dùng bảo bối hắn trao. Để phá cánh cửa lớn giữa không trung trên Linh Sơn, Vân Tước Tử dùng phù văn từ mũ rơm còn lão già âm trầm thi triển Lục Dục Thiên Ma quyết ép hai người Tiên Di Tộc tự bạo, cuối cùng Vân Tước Tử ấn quyết xuyên thủng cửa. Đoàn người lần lượt nhảy vào kim sắc thế giới, Vương Lâm là người thứ tư tiến qua khe cửa. Trong cung điện giữa không trung, Kim Giáp Đại Hán xuất hiện dâng cả biển vàng nuốt đảo và chém trăm đạo kiếm khí đánh lui Vân Tước Tử khiến hắn hoá lưu tinh trốn xuống đáy biển. Khi Đại Hán quay sang chém con khỉ nhỏ, hồng quang trong mắt khỉ tràn hơn ba thước với khí thế độc ác làm thân hắn chấn động kiếm chậm lại, rồi con khỉ lùi về theo lão già âm trầm trầm xuống lòng biển. @c0431"},{"chuong":432,"tieuDe":"Sát Khí","tomTat":"Trước cung điện dưới lòng biển, Kim giáp đại hán khổng lồ canh giữ, vung cự kiếm chém kiếm quang trăm trượng làm cửa ải thử tư cách tu sĩ muốn tiến vào; Chu Vũ Thái và Tử Tâm lén đi đáy biển liền bị quét trúng văng ra, Chu Vũ Thái phun tiên huyết tái nhợt. Kiền Phong rủ Vương Lâm (dưới biệt danh \"Tằng Ngưu\") cùng Liễu Mi liên thủ, nhưng Vương Lâm cố ý đòi một mình hứng kiếm quang trước nhằm dụ Kiền Phong vào vòng mười trượng. Vốn thèm muốn Thập Ức Tôn Hồn Phiên, Kiền Phong đổi ý quyết giết Vương Lâm đoạt bảo, còn Liễu Mi vô tình cố ý đứng nhìn không cứu. Vương Lâm sớm đoán được phản trắc: hắn tế bảo tháp mang thần thức Chu Dật làm kiếm quang đình trệ rồi thoát ly, biến Kiền Phong thành kẻ gần kiếm mang nhất nên bị kiếm quang chuyển hướng giáng xuống, buộc phải xuất dùi đỏ chống đỡ. Tiếp đó Vương Lâm tự bạo toàn bộ tượng gỗ Tuế Nguyệt làm chậm Liễu Mi, dồn hai đạo kiếm quang hợp một cùng một đạo cấm khí đánh nàng rồi lao thẳng vào lòng biển không xem kết quả. Bị Kim giáp đại hán chém kiếm quang truy đuổi, Vương Lâm chịu đau đớn thiên linh cái, dùng rìu chiến và bảo tháp câu giờ, cuối cùng vượt năm mươi trượng vào trong cung điện, nuốt đan dược cùng tiên ngọc áp chế nội thương rồi tiến sâu vào trong. @c0432"},{"chuong":433,"tieuDe":"Diệp Vô Ưu","tomTat":"Trên mặt biển, Liễu Mi phun sương trắng dùng dải ruy băng phá cấm chế thoát khỏi kiếm quang, còn Kiền Phong cũng chật vật né thoát do cơ chế thủ hộ chỉ cho người chống đỡ được một đạo kiếm quang mới được vào cung điện. Hai người sinh mâu thuẫn: Kiền Phong thề bằm Tằng Ngưu làm vạn đoạn, trách Liễu Mi câu kết với hắn rồi tiết lộ Lão gia hỏa từng cấp cho mình một vật đối kháng Thập Ức Tôn Hồn Phiên, định liều mạng đoạt mệnh hồn khi Vân Tước Tử ra ngoài. Trong thông đạo dưới đáy biển, Vương Lâm cẩn thận tiến sâu và thấy nơi tận cùng là tòa tháp cao đặt xác Diệp Vô Ưu — Chu Tước đời đầu tiên đã chết nhưng khí tức ngập trời vẫn khiến hắn suýt quỳ lễ bái, trước xác là đốm tử quang được cho là Tu Tinh Chi Tinh. Vương Lâm sinh nghi vì thần thức không cảm nhận được mệnh hồn bên trong dù bề ngoài giống lời Tư Đồ Nam mô tả. Vân Tước Tử giả bộ trọng thương như đèn hết dầu, viện cớ đã vây khốn lão già Âm Sâm để dụ Vương Lâm mang bảo vật tới Tiên Di Tộc. Vương Lâm lập tức lùi chạy, ngưng tụ Thập Ức Tôn Hồn Phiên rồi vạch trần đó là vật giả và rằng kẻ còn thuấn di được thì thương thế chẳng nặng như lời nói. @c0433"},{"chuong":434,"tieuDe":"Cướp Đoạt","tomTat":"Vân Tước Tử cười tán thưởng tiết lộ vật trên tháp chỉ là 'tinh dẫn' mồi nhử chứ không phải Tu Tinh Chi Tinh thật, hứa đưa Vương Lâm tới tế đàn viễn tổ Tiên Di tộc để tăng một tầng tu vi nếu chịu ra tay thay. Vương Lâm bình tĩnh đòi ngọc giản ghi phương pháp dùng mũ rơm năm xưa làm vật đặt cọc rồi mới hóa cầu vồng bay lên tháp, nhưng khi tới trước Diệp Vô Ưu hắn phát hiện mình đứng cạnh tử quang mà không có bóng nên quyết lật kèo, kích Thập Ức Tôn Hồn Phiên thả hồn phách tấn công cái bóng phía sau ngai vàng thay vì chạm tinh dẫn. Cái bóng sụp đổ, một lão già âm trầm bị Thác Sâm đoạt xá cùng con khỉ nhỏ bước ra; Vân Tước Tử bày phù văn vàng Ảnh cấm vây hãm rồi nhắm vào con khỉ — chỗ giấu 'phân thức' thật. Bảo tháp rung chuyển nứt như rồng phá, ngai vàng tách đôi và thân Diệp Vô Ưu hóa tro, từ đó một kết tinh trắng nửa nắm tay với linh hồn dao động bên trong — Tu Tinh Chi Tinh thật — bay ra khiến mọi người ngừng tranh đấu. Vân Tước Tử cùng lão già và con khỉ lao vào cướp đoạt, riêng Vương Lâm cắn răng từ bỏ, dùng Hồn Phiên bao thân chạy về thông đạo. Lão già âm trầm ôm được tinh thạch liền biến sắc không buông tay được, cả thân hóa bụi khói chui vào trong, rồi một đạo hồng quang bay tới dung hợp với con khỉ nhỏ @c0434."},{"chuong":435,"tieuDe":"Kế Thừa Chu Tước","tomTat":"Kết tinh Tu Tinh Chi Tinh có linh tính bỏ qua con khỉ nhỏ lẫn Vân Tước Tử, nhằm thẳng Vương Lâm truy đuổi vào thông đạo dưới lòng biển, kéo theo cuộc rượt bắt của Vân Tước Tử và tiểu hầu. Tinh thạch chui vào người Vương Lâm, tuôn ký ức Diệp Vô Ưu lĩnh Chu Tước Ấn tại Tiên Ấn Phủ, hồng quang bao phủ giúp hắn tăng tốc phi thường; nhưng khi thanh âm uy nghiêm hỏi có nguyện làm Chu Tước phong hào, Vương Lâm dứt khoát đáp \"Không muốn\" nên truyền thừa rút lui. Qua phù văn quỷ dị, hắn hiểu muốn thu hồi mệnh hồn phải lấy một mạng đổi một mạng hoặc chờ linh vật hấp thu rồi giết đoạt, đồng thời xác định vật này vô quan với Cực Cảnh. Vương Lâm ném tinh thạch về phía Kiền Phong và Liễu Mi, buộc Kiền Phong tế Đồng nhân; Đồng nhân hút tiên huyết cùng thọ nguyên Kiền Phong, ngưng hóa thành Chu Tước Tử hình hài hồng nhuận dung nhập tinh thạch rồi tản sương hồng bao vây đại chiến Vân Tước Tử. Bên ngoài lộ ra bí mật Chu Tước Tử nhiều đời mưu đoạt xá Kiền Phong để né luân hồi thiên đạo, song Đồng nhân vẫn còn sơ hở trí mạng. Vương Lâm chộp Thập Ức Tôn Hồn Phiên dung hợp sáu chủ hồn, vung chiến phủ đánh tan Chu Tước Trùy, ép Kiền Phong mở Chu Tước huyền trận quyết chiến. @c0435"},{"chuong":436,"tieuDe":"Chiến Kiền Phong","tomTat":"Vương Lâm dùng Thập Ức Tôn Hồn Phiên phóng sáu chủ hồn vây đả Kiền Phong và Liễu Mi; Liễu Mi nhả dải áo tơ tằm thêu kim tuyến phá vây hóa luồng sáng trắng bỏ trốn, bị bốn chủ hồn có cả tàn hồn Kỳ Lân đuổi giết. Kiền Phong lần lượt dùng quạt đỏ khắc chế hồn phách, song bị bốn vỏ kiếm của Vương Lâm chém nát rồi nhờ Chu Tước huyền trận chặn được hai chủ hồn. Hắn tiếp tục thi triển khối gỗ xanh quỷ dị tự khắc thân ảnh, giam cầm và phóng đao ảnh suýt giết Vương Lâm, nhưng Vương Lâm cho một chủ hồn tự bạo phá vây né đòn. Vương Lâm tụ hồn phách thành vòng vây mười dặm, bốn vỏ kiếm hóa đen lao từ bốn hướng, tuyên bố giết Kiền Phong vì đã đáp ứng Hồng Điệp. Đường cùng, Kiền Phong lấy ra thanh thiết kiếm cũ của lão tổ Kiền gia do một đời Chu Tước Tử bí mật lưu lại; Vương Lâm nhận ra trên kiếm có máu Cổ Thần thật sự nên ngưng trọng nhận định vật này tuyệt không tầm thường. @c0436"},{"chuong":437,"tieuDe":"Sát Khí Của Thác Sâm","tomTat":"Khi Kiền Phong lấy ra thiết kiếm bí mật của bộ tộc — bảo vật do Chu Tước đời trước giấu ở Kiền Gia để đối kháng Thập Ức Hồn Phiên — một hư ảnh đỏ chứa tiểu Hầu của Thác Sâm (Cửu Tinh tộc) xuyên qua vòng vây linh hồn, đánh Vương Lâm văng nghìn trượng trọng thương, phá Chu Tước Huyền Trận trên người Kiền Phong rồi đoạt lấy thiết kiếm. Thác Sâm rút giọt máu Cửu Tinh tộc dính trên kiếm, nuốt vào rồi biến mất vào đám mây đỏ nơi Chu Tước và Vân Tước giao chiến, định phối hợp Tu Tinh Chi Tinh để thoát vòng vây. Vương Lâm hóa hắc mang quấn linh hồn truy sát Kiền Phong, điểm tay lên mi tâm và dùng Tu Tinh Chi Tinh rút Mệnh Hồn theo cách lấy mạng đổi mạng; Mệnh Hồn Kiền Phong tan vỡ, hắn chết trước khi kịp hoàn thành tự bạo. Vương Lâm chụp được một trong bốn đạo Ngũ Hành Tứ Tinh mà Kiền Phong từng thôn phệ của Hồng Điệp cùng túi trữ vật của hắn. Quan sát từ xa, Tử Tâm tan hết hận ý, kết ấn triệu tu sĩ khôi lỗi hộ pháp và ngưng tụ một cổ khí tức cực giống Kiền Phong, trong khi Chu Vũ Thái độc thoại về bí mật Lô Đỉnh và việc giết Kiền Phong vô tình thành toàn cho Tử Tâm. Cuối chương, cả Vân Tước lẫn Chu Tước đều bị ném khỏi đám mây đỏ, người miệng chảy máu mắt đục ngàu, kẻ sắc mặt âm trầm tử khí nồng đậm trước khi mất sinh cơ @c0437."},{"chuong":438,"tieuDe":"Sứ Giả Tu Chân Liên Minh","tomTat":"Phân thức hư ảnh đoạt máu Cổ Thần của Thác Sâm đuổi kịp Vương Lâm, phá vỡ lưỡi Chiến Phủ và định thôn phệ ký ức truyền thừa của hắn. Vương Lâm dung hợp toàn bộ hồn phách trong Thập Ức Tôn Hồn Phiên thành một linh hồn Vấn Đỉnh sơ kỳ để chạy trốn, nhưng bị vòng xoáy hấp lực 'Trở về!' kéo lại; trước cái chết cận kề, hắn kích Pháp quyết toái diệt cho tất cả linh hồn tự bạo, gây trọng thương Thác Sâm và rúng động cả Chu Tước tinh, đổi lấy việc Thập Ức Hồn Phiên bị hủy khiến tu vi rớt xuống Anh Biến sơ kỳ. Đúng lúc đó Sứ Giả Tu Chân Liên Minh đeo mặt nạ từ mặt biển phóng ra, dùng năm xích sắt Phong ấn cắt đứt phân thức Thác Sâm, thu hồi pha lê trắng và thiết kiếm Kiền Phong, rồi tha không truy cứu Chu Tước đã hết tuổi thọ. Sứ Giả tháo mặt nạ lộ thân phận chính là Mặc Trí — người năm xưa cùng Vương Lâm bàn đạo sinh tử ở Cổ Miếu — gọi hắn 'Đại Ngưu huynh', nhưng Vương Lâm từ chối làm Chu Tước với chí hướng 'không dừng ở Chu Tước'. Mặc Trí phân cho Tiên Di tộc một phần ba lãnh thổ đổi lấy xương sọ cửu diệp mỗi nghìn năm, phục hồi Chu Tước mộ và Chu Tước Ấn, rồi xét chọn người kế: Chu Vũ Thái bị loại do tu vi, Tử Tâm — vốn là Lô Đỉnh của Kiền Phong mà Vương Lâm đã giết — được cân nhắc và đe dọa giết hắn, nhưng chùn lại khi Vương Lâm ngụ ý 'nếu ta thành Chu Tước'. Trong khi đó thân thật Thác Sâm ở Huyết Hải Cổ Thần chi địa vẫn còn một giọt máu hồng, thề sẽ thoát ra và không tha Vương Lâm lần sau. @c0438"},{"chuong":439,"tieuDe":"Bức Màn Chu Tước","tomTat":"Trong thân phận Tằng Ngưu, Vương Lâm từ chối làm Chu Tước mà nhường lại cho Chu Vũ Thái để báo ơn, khiến Sứ Giả Mặc Trí cho tinh thạch hình trái tim nhập mi tâm hắn, phong làm đệ thập ngũ Chu Tước rồi lệnh bế quan một năm cảm ngộ Chu Tước Ấn. Mặc Trí để lại ấn ký màu đỏ giúp đưa người ra khỏi Chu Tước mộ rồi đạp hư không phục mệnh Liên Minh Tu Chân, còn Vương Lâm thầm tính nhờ Chu Vũ Thái chăm sóc người thân để mình yên tâm rời đi. Hắn thu ba chủ hồn gồm Kỳ Lân tàn hồn vào Thập Ức Hồn Phiên vốn đã tổn thất nặng, quyết khi rời đi phải giết Liễu Mi vì nàng từng cùng Kiền Phong dồn hắn vào chỗ chết, đồng thời lập mục tiêu tìm Hứa Lập Quốc đoạt cây loan đao và hóa khói xanh bay đi. Một năm sau Chu Tước tinh chìm trong điêu tàn yên tĩnh: Tiên Di Tộc lui về tây bắc, các tông phái thu đồ ồ ạt, Chu Vũ Thái xuất quan với tu vi thấp liền bế quan trong Chu Tước Sơn. Liễu Mi nhờ đệ tứ hồn sư tôn ngầm cho mà sống sót, rời đi và thề chuyển từ Thiên Huyễn Vô Tình Đạo sang Vạn Huyễn Thiên Ma đạo để báo thù khiến Vương Lâm không nhận ra; Tử Tâm cũng lặng lẽ rời tinh. Chương khép lại ở căn lầu cũ của Lý Mộ Uyển tại Vân Thiên Tông, nơi một người áo trắng khí chất kỳ dị, mắt trẻ thơ ẩn vẻ sâu sắc đang nhìn ra cửa sổ. @c0439"},{"chuong":440,"tieuDe":"Một Năm","tomTat":"Sau khi rời Chu Tước mộ, Vương Lâm về Triệu Quốc bế quan đúng một năm, lành hẳn thương thế và củng cố vững Anh Biến sơ kỳ; hắn khéo léo từ chối thiệp mời dự nghi lễ phong hào của Chu Vũ Thái, người đã phát lời thề bảo vệ tất cả những ai có quan hệ với hắn. Hứa Lập Quốc nương trong tiên kiếm đắc ý khoe đã thuần phục được loan đao 'Lão Tứ' tìm thấy ở Chu Tước mộ, rồi dẫn nó ra ngoài dạo chơi, trong khi Vương Lâm vẫn chưa điều khiển nổi thanh đao hợp từ mệnh hồn mạnh mẽ nào đó trên Chu Tước tinh. Tư Đồ Nam — nay đã nhập hoàng cung phàm nhân làm Tự Tình Kiên Vương — báo tin về manh mối Tang Viên thôn ngoài Phượng Hoàng thành của Sở Quốc và hẹn cùng rời đi. Nhìn Chu Như đã trưởng thành duyên dáng, tu tới Ngưng Khí kỳ tầng hai, Vương Lâm chạnh lòng nhớ tới Lý Mộ Uyển và day dứt vì đã tước đi tuổi thơ của nàng. Hắn quyết đưa Chu Như về nhà cha mẹ, dặn dò đạo hiếu rồi tuyên bố duyên phận hai người đã hết; đám mây tăng tốc bay đi giữa tiếng nức nở của Chu Như, còn Tiểu Bạch quyết dù hộc máu cũng phải đuổi kịp. @c0440"},{"chuong":442,"tieuDe":"Luyện Bảo","tomTat":"Khi đóa hồng xanh đi theo Vương Lâm, các đóa hồng trắng trên những tầng băng đồng loạt tàn lụi tiêu tán vì mất ý nghĩa tồn tại. Tại tổ trạch Vương gia dưới chân Hằng Nhạc phái ở Triệu Quốc, Vương Lâm mặc bạch y lặng đứng ba ngày ba đêm trước dãy linh vị, dừng mắt ở hai linh vị cha mẹ, ký ức cuồn cuộn rồi quỳ dập đầu từ biệt. Bên ngoài từ đường, Vương Trác dẫn hơn trăm con cháu Vương gia quỳ tiễn; Vương Lâm dặn dò xong đạp một bước biến mất, Vương Trác hồi tưởng lần đầu gặp thiếu niên Vương Lâm bên Nhị thúc mà rơi l��, nhắc thoáng cái đã qua sáu trăm năm. Vương Lâm cưỡi Văn Thú đến cánh đồng hoang phía đông Chu Tước tinh, triệu Lôi Oa và Văn Thú rồi soát túi trữ vật chọn pháp bảo cần tế luyện. Hắn khoanh chân thổi khí Nguyên Thần bọc bốn vỏ kiếm ba ngày, thiết lập liên hệ chặt với nội tâm; sau đó dùng bảo tháp ẩn thần thức Chu Dật cùng Nguyên thần bảy ngày để xóa tia thần thức cũ trên Côn Cực Tiên và lưu dấu ấn của mình. Vương Lâm nhận ra trong Côn Cực Tiên có nhiều trận pháp giống mũ cỏ, sinh cấm chế và nâng hiệu quả Cấm Phiên một tầng, phục vụ mục tiêu tích đủ 9999 cấm chế. Hắn xác định Côn Cực Tiên là Tiên Bảo ngưng tụ tiên lực nhưng uy lực quỷ dị, không cần linh lực mà tự ẩn một lực lượng kỳ dị khiến nó càng thần bí trong mắt hắn."},{"chuong":444,"tieuDe":"Giao Dịch Tinh","tomTat":"Khoảnh khắc Vương Lâm bay vào tinh không rời Chu Tước Tinh, khắp nơi có liên hệ với hắn đều ngẩng đầu cảm nhận: Vương Trác ở Triệu Quốc than nhẹ và gọi hắn là người đệ đệ cả đời lão kính phục nhất, con hổ trong khe núi Sở Quốc khoan khoái, Tiểu Bạch vẫn đợi Chu Như, còn Chu Như ngồi cùng phụ mẫu ở thôn Phượng Hoàng mơ hồ thấy thúc thúc rời xa như cả một đời. Trên Chu Tước Tinh, Vân Tước Tử già nua vì tổn thọ sau Chu Tước mộ thở dài “Hậu sinh khả úy”, thiếu tộc trưởng Tiên Di Tộc bùi ngùi muốn rời đi, tiếng kêu gọi của tổ tiên Cự Ma Tộc vẫn vang từ Thi Âm Tông dưới lòng đất, còn Thác Sâm trong Cổ Thần chi địa cười lớn vì sắp thoát vây. Vương Lâm cưỡi Tinh La Bàn cùng Tư Đồ Nam lên đường, hai người định ghé Giao Dịch Tinh rồi tách ra — Tư Đồ Nam đến Phượng Loan Tinh làm thân vương, Vương Lâm tìm tài liệu hoàn thiện Tinh La Bàn vốn còn thiếu vật liệu. Trên đường, hắn ghé Nguyệt Tinh thu hồi bản tôn tóc đỏ da cổ đồng, dung hợp đạt đỉnh Anh Biến trung kỳ. Suốt một tháng kế tiếp Tư Đồ Nam đem hết pháp thuật thần thông ra đấu pháp truyền dạy, Vương Lâm từ chật vật dần khắc phục nhược điểm và đánh ngang tay, khiến lão phải đề cao tu vi lên mức Anh Biến hậu kỳ."},{"chuong":445,"tieuDe":"Khôn Mộc Thạch","tomTat":"Trong điều kiện không dùng pháp bảo, Vương Lâm không địch lại Tư Đồ Nam; lão chỉ ra kinh nghiệm chiến đấu của hắn với tu sĩ Anh Biến hậu kỳ và Vấn Đỉnh còn quá ít, rồi tăng tu vi lên Vấn Đỉnh sơ kỳ, bắt hắn chỉ được tránh né và chạy trốn để rèn luyện. Kiểu khổ luyện tàn khốc kéo dài một tháng, nhờ cơ thể đạt tam tinh Cổ Thần sau khi dung hợp bản tôn nên Vương Lâm không liên tục trọng thương mà tiến bộ rõ rệt. Họ đến Giao Dịch Tinh — một tinh cầu tu chân màu xanh có vòng sáng bao quanh; Tư Đồ Nam xác nhận nơi này như năm xưa lão rời đi, không ai mạnh bằng lão, liền quyết 'đoạt tháp', rồi đuổi ba đạo cầu vồng tìm tới và rời đi, hẹn ba ngày sau quay lại. Vương Lâm hóa khói xanh khám phá tinh cầu, phát hiện Minh Hồng thành khổng lồ như mãnh thú nằm sấp, toàn người tu chân với chợ tự do phía tây và chín gian hàng xa hoa ở thành Bắc. Hắn vào thành qua cửa Đông để mua vật liệu sửa Tinh La Bàn thì bị thanh niên nhỏ con Lý Đan Nam âm thầm bám theo. Lý Đan Nam mời chỉ đường với giá mười khối thượng phẩm linh thạch, nhận ra Khôn Mộc Thạch là vật thuộc tính mộc sống trên nham thạch mười năm mọc một tấc, khuyên đừng mua vì đắt mà ít dụng; Vương Lâm vẫn quyết mua và bảo dẫn vào phường thị tự do phía tây thành."}];
